package com.restaurantcraft.menu; import com.restaurantcraft.blockentity.RestaurantManagementBlockEntity; import com.restaurantcraft.registry.ModMenuTypes; import net.minecraft.world.entity.player.*; import net.minecraft.world.inventory.*; import net.minecraft.world.item.ItemStack; import net.minecraftforge.items.SlotItemHandler; public class RestaurantManagementMenu extends AbstractContainerMenu { public final RestaurantManagementBlockEntity be; public RestaurantManagementMenu(int id, Inventory inv, RestaurantManagementBlockEntity be){super(ModMenuTypes.RESTAURANT_MANAGEMENT.get(),id);this.be=be; for(int i=0;i<9;i++)addSlot(new SlotItemHandler(be.menuInventory,i,8+i*18,36)); for(int r=0;r<3;r++)for(int c=0;c<9;c++)addSlot(new SlotItemHandler(be.fridgeInventory,c+r*9,8+c*18,70+r*18)); addPlayer(inv,8,140);} void addPlayer(Inventory inv,int x,int y){for(int r=0;r<3;r++)for(int c=0;c<9;c++)addSlot(new Slot(inv,c+r*9+9,x+c*18,y+r*18));for(int c=0;c<9;c++)addSlot(new Slot(inv,c,x+c*18,y+58));} public boolean stillValid(Player p){return be.canAccess(p);} public ItemStack quickMoveStack(Player p,int i){return ItemStack.EMPTY;} }
